class Solution:
    def secondGreaterElement(self, nums):
        n = len(nums)
        ans = [-1] * n
        first = []
        second = []
        for i, v in enumerate(nums):
            while second and nums[second[-1]] < v:
                ans[second.pop()] = v
            promote = []
            while first and nums[first[-1]] < v:
                promote.append(first.pop())
            while promote:
                second.append(promote.pop())
            first.append(i)
        return ans

