var secondGreaterElement = function(nums) {
    const n = nums.length;
    const ans = new Array(n).fill(-1);
    const first = [];
    const second = [];
    for (let i = 0; i < n; i++) {
        const v = nums[i];
        while (second.length && nums[second[second.length - 1]] < v) {
            ans[second.pop()] = v;
        }
        const promote = [];
        while (first.length && nums[first[first.length - 1]] < v) {
            promote.push(first.pop());
        }
        while (promote.length) second.push(promote.pop());
        first.push(i);
    }
    return ans;
};
